const loopbackHostnames = new Set(['127.0.0.1', '::1', '[::1]', 'localhost']);

const parseOrigin = (value: string, label: string): URL => {
  const trimmedValue = value.trim();
  if (!trimmedValue) {
    throw new Error(`${label} is required`);
  }

  const url = new URL(trimmedValue);
  if (
    !url.hostname ||
    url.pathname !== '/' ||
    url.search ||
    url.hash ||
    url.username ||
    url.password
  ) {
    throw new Error(`${label} must be an origin without credentials or a path`);
  }

  return url;
};

export const normalizeTenantDomain = (value: string): string => {
  const trimmedValue = value.trim().toLowerCase();
  if (!trimmedValue) {
    throw new Error('Domain is required');
  }

  const url = new URL(
    trimmedValue.includes('://') ? trimmedValue : `https://${trimmedValue}`,
  );
  if (
    !url.hostname ||
    url.pathname !== '/' ||
    url.port ||
    url.search ||
    url.hash ||
    url.username ||
    url.password
  ) {
    throw new Error('Domain must be a single host name');
  }

  return url.hostname;
};

export const normalizeTenantCanonicalRootUrl = (
  value: string,
  primaryDomain: string,
): string => {
  const normalizedDomain = normalizeTenantDomain(primaryDomain);
  const url = parseOrigin(value, 'Canonical root URL');

  if (url.protocol !== 'https:') {
    throw new Error('Canonical root URL must use HTTPS');
  }
  if (url.port) {
    throw new Error('Canonical root URL must not use a non-default port');
  }
  if (url.hostname !== normalizedDomain) {
    throw new Error('Canonical root URL must match the primary domain');
  }

  return url.origin;
};

const normalizeLoopbackDevelopmentOrigin = (value: string): string | null => {
  try {
    const url = parseOrigin(value, 'BASE_URL');
    if (
      (url.protocol !== 'http:' && url.protocol !== 'https:') ||
      !loopbackHostnames.has(url.hostname.toLowerCase())
    ) {
      return null;
    }

    return url.origin;
  } catch {
    return null;
  }
};

export const resolveTenantPublicOrigin = ({
  baseUrl,
  canonicalRootUrl,
  nodeEnvironment,
  primaryDomain,
}: {
  baseUrl: string | undefined;
  canonicalRootUrl: string;
  nodeEnvironment: string | undefined;
  primaryDomain: string;
}): string => {
  const canonicalOrigin = normalizeTenantCanonicalRootUrl(
    canonicalRootUrl,
    primaryDomain,
  );
  const normalizedEnvironment = nodeEnvironment?.trim().toLowerCase();
  const canUseDevelopmentOverride =
    normalizedEnvironment === 'development' || normalizedEnvironment === 'test';

  if (canUseDevelopmentOverride && baseUrl) {
    return normalizeLoopbackDevelopmentOrigin(baseUrl) ?? canonicalOrigin;
  }

  return canonicalOrigin;
};
import { describe, expect, it } from 'vitest';

import {
  normalizeTenantCanonicalRootUrl,
  normalizeTenantDomain,
  resolveTenantPublicOrigin,
} from './tenant-origin';

describe('tenant origin', () => {
  it('normalizes primary domains and matching HTTPS canonical origins', () => {
    expect(normalizeTenantDomain(' HTTPS://Section.Example.Org:443 ')).toBe(
      'section.example.org',
    );
    expect(
      normalizeTenantCanonicalRootUrl(
        ' https://Section.Example.Org:443 ',
        'section.example.org',
      ),
    ).toBe('https://section.example.org');
  });

  it.each([
    'http://section.example.org',
    'https://other.example.org',
    'https://section.example.org:8443',
    'https://user@section.example.org',
    'https://section.example.org/events',
    'https://section.example.org?next=/events',
    'https://section.example.org#events',
  ])('rejects unsafe canonical roots: %s', (canonicalRootUrl) => {
    expect(() =>
      normalizeTenantCanonicalRootUrl(
        canonicalRootUrl,
        'section.example.org',
      ),
    ).toThrow();
  });

  it('uses a loopback BASE_URL only in development and test', () => {
    const input = {
      baseUrl: 'http://localhost:4200',
      canonicalRootUrl: 'https://section.example.org',
      primaryDomain: 'section.example.org',
    } as const;

    expect(
      resolveTenantPublicOrigin({ ...input, nodeEnvironment: 'development' }),
    ).toBe('http://localhost:4200');
    expect(
      resolveTenantPublicOrigin({ ...input, nodeEnvironment: 'test' }),
    ).toBe('http://localhost:4200');
    expect(
      resolveTenantPublicOrigin({ ...input, nodeEnvironment: 'production' }),
    ).toBe('https://section.example.org');
  });

  it('ignores non-loopback BASE_URL values and validates canonical config first', () => {
    expect(
      resolveTenantPublicOrigin({
        baseUrl: 'https://attacker.example',
        canonicalRootUrl: 'https://section.example.org',
        nodeEnvironment: 'development',
        primaryDomain: 'section.example.org',
      }),
    ).toBe('https://section.example.org');

    expect(() =>
      resolveTenantPublicOrigin({
        baseUrl: 'http://localhost:4200',
        canonicalRootUrl: 'https://attacker.example',
        nodeEnvironment: 'development',
        primaryDomain: 'section.example.org',
      }),
    ).toThrow('Canonical root URL must match the primary domain');
  });
});

