import { afterAll, beforeAll, describe, expect, it } from '@effect/vitest';
import { randomUUID } from 'node:crypto';
import { Pool, type PoolClient } from 'pg';

import { createNodePgPoolConfig } from '../pg-connection-config';

const databaseUrl = process.env['REGISTRATION_CONCURRENCY_DATABASE_URL'];
const neonLocalProxy =
  process.env['REGISTRATION_CONCURRENCY_NEON_LOCAL_PROXY'] === 'true';
const describeWithPostgres = databaseUrl ? describe : describe.skip;
const schemaName = `registration_concurrency_${randomUUID().replaceAll('-', '')}`;
const qualified = (table: string) => `"${schemaName}"."${table}"`;

const settleCompetingInsert = async ({
  first,
  insertSql,
  second,
}: {
  first: PoolClient;
  insertSql: string;
  second: PoolClient;
}) => {
  await first.query('BEGIN');
  await second.query('BEGIN');
  await first.query(insertSql);

  const competingInsert = second.query(insertSql).then(
    () => null,
    (error: unknown) => error,
  );
  await first.query('COMMIT');
  const competingError = await competingInsert;
  await second.query('ROLLBACK');

  return competingError;
};

describeWithPostgres('registration persistence concurrency invariants', () => {
  const pool = new Pool(
    databaseUrl
      ? createNodePgPoolConfig({ databaseUrl, neonLocalProxy })
      : undefined,
  );

  beforeAll(async () => {
    await pool.query(`CREATE SCHEMA "${schemaName}"`);
    await pool.query(`
      CREATE TABLE ${qualified('event_registrations')} (
        id text PRIMARY KEY,
        tenant_id text NOT NULL,
